const TASKS=[
  {id:"selig-1",sector:"berg",type:"puzzle",difficulty:1,title:"Seligpreisungen-Puzzle",story:"Sechs Textstücke liegen als Puzzle-Pieces vor. Setzt sie in die Reihenfolge des Luthertextes.",source:"Mt 5,3-10 nach Luther 1912: geistlich arm, Leid tragen, Sanftmütige, hungert und dürstet nach der Gerechtigkeit, Barmherzige, Friedfertige.",question:"Klickt die Puzzleteile in der richtigen Reihenfolge an. Ein falsch gesetztes Teil kann wieder gelöst werden.",items:["geistlich arm","Leid tragen","Sanftmütige","hungert und dürstet nach der Gerechtigkeit","Barmherzige","Friedfertige"],correct:["geistlich arm","Leid tragen","Sanftmütige","hungert und dürstet nach der Gerechtigkeit","Barmherzige","Friedfertige"],rewards:{frieden:2,gerechtigkeit:5,vertrauen:2},card:{type:"Seligpreisungs-Karte",name:"Friedfertige"},success:"Ihr habt die Textbewegung erkannt: Zuspruch wird Schritt für Schritt zur Haltung.",hint:"Schaut auf die genaue Reihenfolge im Hilfetext. Beginnt bei 'geistlich arm'."},
  {id:"selig-2",sector:"berg",type:"cards",difficulty:2,title:"Seligpreisungs-Karten: Verheißung prüfen",story:"Die Karten funktionieren nur, wenn ihr zuerst die genaue Verheißung aus Mt 5 erkennt. Danach könnt ihr deuten, welche Haltung daraus folgt.",source:"Mt 5,6-9 nach Luther 1912: hungert und dürstet nach der Gerechtigkeit; Barmherzige; reines Herzens; Friedfertige.",question:"Legt zu jeder Seligpreisungs-Karte die passende Verheißung. Die Ablenkungen klingen fromm, stehen aber so nicht im Text.",items:[["hungert und dürstet nach der Gerechtigkeit","sie sollen satt werden"],["Barmherzige","sie werden Barmherzigkeit erlangen"],["reines Herzens","sie werden Gott schauen"],["Friedfertige","sie werden Gottes Kinder heißen"]],correct:["sie sollen satt werden","sie werden Barmherzigkeit erlangen","sie werden Gott schauen","sie werden Gottes Kinder heißen"],rewards:{frieden:5,gerechtigkeit:6,vertrauen:3},card:{type:"Seligpreisungs-Karte",name:"Verheißung lesen"},success:"Sehr gut: Ihr habt nicht geraten, sondern die Verheißungen aus dem Bibeltext herausgelesen. Erst daraus entsteht eine belastbare Deutung.",hint:"Lest Mt 5,6-9 langsam: Nach dem Semikolon steht jeweils die Verheißung. Nicht jede schöne Deutung ist die Textlösung."},
  {id:"selig-3",sector:"berg",type:"levels",difficulty:3,title:"Seligpreisungen anwenden",story:"Eine Gruppe aus der Klasse erlebt, dass jemand wegen eines Konflikts ausgegrenzt wird. Ihr prüft nun in mehreren Leveln, was Mt 5 unter Frieden und Gerechtigkeit versteht.",source:"Mt 5,6.7.9-10 nach Luther 1912: Selig sind, die da hungert und dürstet nach der Gerechtigkeit; Barmherzige; Friedfertige; die um Gerechtigkeit willen verfolgt werden.",question:"Bearbeitet die Level der Reihe nach. Nutzt den Bibeltext, um Zuspruch, Entscheidung und Transfer zu verbinden.",levels:[{title:"Level 1: Textsignal erkennen",q:"Welche Seligpreisung passt am genauesten, wenn jemand für eine gerechte Klärung Nachteile riskiert?",answers:["Selig sind, die um Gerechtigkeit willen verfolgt werden.","Selig sind, die immer Streit vermeiden.","Selig sind, die am schnellsten nachgeben."],correct:0},{title:"Level 2: Entscheidung treffen",q:"Welche Handlung verbindet Friedfertigkeit und Gerechtigkeit?",answers:["Unrecht benennen, Betroffene schützen und ein Gespräch ohne Beschämung vorbereiten.","Alle bitten, nichts mehr zu sagen, damit Ruhe ist.","Die Gegenseite öffentlich bloßstellen, damit es gerecht wirkt."],correct:0},{title:"Level 3: Alltag übertragen",q:"Was wäre ein tragfähiger erster Satz in einer heutigen Konfliktsituation?",answers:["Wir wollen klären, was passiert ist, ohne jemanden lächerlich zu machen.","Das war bestimmt nicht so schlimm, vergessen wir es.","Wer angefangen hat, muss jetzt allein die Folgen tragen."],correct:0},{title:"Level 4: Reflexion",q:"Welche Begründung passt am besten zu Mt 5?",answers:["Frieden wird nicht gegen Gerechtigkeit ausgespielt; er schützt Menschen und sucht Versöhnung.","Frieden bedeutet, dass niemand mehr über Unrecht spricht.","Gerechtigkeit bedeutet, dass eine Seite vollständig gewinnt."],correct:0}],rewards:{frieden:7,gerechtigkeit:8,vertrauen:3},card:{type:"Seligpreisungs-Karte",name:"Frieden mit Gerechtigkeit"},success:"Ihr habt die Progression verstanden: Textsignal erkennen, gerecht handeln, friedlich übertragen.",hint:"Achtet darauf, dass Mt 5 Frieden und Gerechtigkeit nicht trennt. Ruhe allein ist noch kein Frieden."},
  {id:"anti-1",sector:"tiberias",type:"match",difficulty:1,title:"Ihr habt gehört / Ich aber sage",story:"Die Antithesen verschieben den Blick von äußerer Regelbefolgung auf die Wurzel des Handelns.",source:"Mt 5,21-44 nach Luther 1912: Bruderzorn, Versöhnung vor der Gabe, Ja ja / nein nein, nicht Vergeltung, Feindesliebe.",question:"Ordnet Jesu Zuspitzung dem passenden Themenfeld zu.",items:[["Du sollst nicht töten","Schon Zorn gegen den Bruder macht sichtbar, dass Gemeinschaft innerlich zerbricht."],["Gabe auf dem Altar","Versöhnung mit dem Bruder hat Vorrang vor religiöser Selbstbestätigung."],["Schwören","Wahrhaftigkeit braucht kein großes Absichern: Eure Rede sei Ja, ja; nein, nein."],["Feindesliebe","Der Gegner bleibt ein Mensch vor Gott; Gebet unterbricht die Logik der Vergeltung."]],correct:["Schon Zorn gegen den Bruder macht sichtbar, dass Gemeinschaft innerlich zerbricht.","Versöhnung mit dem Bruder hat Vorrang vor religiöser Selbstbestätigung.","Wahrhaftigkeit braucht kein großes Absichern: Eure Rede sei Ja, ja; nein, nein.","Der Gegner bleibt ein Mensch vor Gott; Gebet unterbricht die Logik der Vergeltung."],rewards:{frieden:5,gerechtigkeit:4,vertrauen:3},card:{type:"Tugend-Karte",name:"Wahrhaftigkeit"},success:"Ihr erkennt die Struktur: Jesus fragt nach dem Herzen des Handelns, nicht nur nach sichtbarer Regelverletzung.",hint:"Sucht im Bibeltext die Sätze nach 'Ich aber sage euch' und danach, was sie vertiefen."},
  {id:"anti-2",sector:"tiberias",type:"quest",difficulty:2,title:"Moralquest: Streit im Tor",story:"Eine Gruppe wurde beleidigt. Einige wollen zurückschlagen, andere wollen alles zudecken. Beides reicht dem Text nicht.",source:"Mt 5,22-24.39 nach Luther 1912: Zorn zerstört; Versöhnung geht vor die Gabe; die Backe hinhalten unterbricht Vergeltung.",question:"Wählt die drei Schritte, die der Antithesen-Logik am ehesten entsprechen.",answers:["Gegenbeleidigung sammeln, damit die andere Seite merkt, wie es sich anfühlt.","Gefahr stoppen und räumlichen Abstand schaffen, ohne Rache zu planen.","Zorn und Unrecht benennen, ohne die andere Seite zu entwürdigen.","Ein Gespräch mit Wiedergutmachung vorbereiten, bevor man zur Tagesordnung übergeht.","Den Konflikt religiös überdecken: Hauptsache, nach außen wirkt alles friedlich."],correct:[1,2,3],rewards:{frieden:7,gerechtigkeit:6,vertrauen:2},card:{type:"Tugend-Karte",name:"Versöhnung"},success:"Richtig: Schutz, Wahrheit und Versöhnung gehören zusammen. Keine Rache, aber auch kein frommes Zudecken.",hint:"Der Text verbindet Zornkritik und Versöhnungsauftrag. Welche Schritte verhindern Vergeltung und ermöglichen Wahrheit?"},
  {id:"anti-3",sector:"tiberias",type:"chat",difficulty:3,title:"Chat: Feindesliebe ohne Naivität",story:"Ihr seid in einem Gruppenchat. Nach einer Beleidigung kippt die Stimmung. Eure Antworten entscheiden, ob der Chat in Vergeltung, Schweigen oder Klärung führt.",source:"Mt 5,39.44 nach Luther 1912: Widerstrebet nicht dem Übel; liebet eure Feinde; bittet für die, so euch beleidigen und verfolgen.",question:"Führt den Chat Schritt für Schritt. Wählt die Antwort, die Schutz, Wahrheit und Verzicht auf Rache verbindet.",chat:[{from:"Mara",text:"Das war unfair. Wenn wir nichts tun, geht das weiter.",choices:["Dann zahlen wir es ihnen morgen heim.","Wir sichern zuerst Schutz und sammeln ruhig, was passiert ist.","Ignorieren. Feindesliebe heißt, alles auszuhalten."],correct:1,reply:"Schutz zuerst. So wird Feindesliebe nicht zur Verharmlosung."},{from:"Jona",text:"Aber wenn wir Beweise sammeln, klingt das doch wieder nach Gegenangriff.",choices:["Wir benennen Unrecht, ohne die andere Seite zu entwürdigen.","Wir posten Screenshots in den Klassenchat.","Wir reden nur noch mit denen, die auf unserer Seite sind."],correct:0,reply:"Wahrheit ohne Beschämung unterbricht die Vergeltung."},{from:"Mara",text:"Und was machen wir mit denen, die uns beleidigt haben?",choices:["Wir bitten um ein Gespräch mit Wiedergutmachung und bleiben bei klaren Grenzen.","Wir tun so, als wäre nichts gewesen.","Wir schließen sie ab jetzt aus allem aus."],correct:0,reply:"Grenzen, Umkehr und Gebet gehören zusammen."}],rewards:{frieden:8,gerechtigkeit:7,vertrauen:3},card:{type:"Tugend-Karte",name:"Feindesliebe ohne Naivität"},success:"Der Chat bleibt anspruchsvoll: keine Rache, keine Verharmlosung, sondern Schutz und Versöhnung.",hint:"Die tragfähige Antwort hält drei Dinge zusammen: Schutz für Betroffene, Wahrheit über Unrecht, Verzicht auf Vergeltung."},
  {id:"vater-1",sector:"see",type:"puzzle",difficulty:1,title:"Vaterunser-Puzzle",story:"Die Bitten des Vaterunsers sind nicht zufällig angeordnet. Sie beginnen bei Gott und führen in menschliche Not.",source:"Mt 6,9-13 nach Luther 1912: Dein Name, dein Reich, dein Wille, täglich Brot, Schuldvergebung, Versuchung, Erlösung.",question:"Bringt sechs Bitten in die Reihenfolge des Luthertextes.",items:["Dein Name werde geheiligt","Dein Reich komme","Dein Wille geschehe auf Erden wie im Himmel","Unser täglich Brot gib uns heute","Vergib uns unsere Schuld, wie wir unsern Schuldigern vergeben","Führe uns nicht in Versuchung, sondern erlöse uns von dem Übel"],correct:["Dein Name werde geheiligt","Dein Reich komme","Dein Wille geschehe auf Erden wie im Himmel","Unser täglich Brot gib uns heute","Vergib uns unsere Schuld, wie wir unsern Schuldigern vergeben","Führe uns nicht in Versuchung, sondern erlöse uns von dem Übel"],rewards:{frieden:2,gerechtigkeit:3,vertrauen:7},card:{type:"Gleichnis-Karte",name:"Gebet als Ausrichtung"},success:"Gut gepuzzelt: Das Gebet richtet zuerst auf Gott aus und wird dann konkret bei Brot, Schuld und Bewahrung.",hint:"Achtet im Text auf die Wechselbewegung: Gottes Name/Reich/Wille, dann Brot, Schuld und Bewahrung."},
  {id:"vater-2",sector:"see",type:"wimmel",difficulty:2,title:"Wimmelbild: Reich, Brot, Schuld",story:"Im neuen KI-Wimmelbild sind Zeichen und Ablenkungen dichter in die Szene eingebaut. Ihr müsst suchen und danach mit Mt 6 begründen.",source:"Mt 6,9-13.19-21.33 nach Luther 1912: täglich Brot, Schuldvergebung, Reich Gottes, Gottes Gerechtigkeit; Schätze auf Erden sind eine Warnung.",question:"Findet vier passende Zeichen: Versorgung, Vergebung, Gerechtigkeit und Gebet. Lasst zwei Ablenkungen unmarkiert.",image:"assets/images/wimmelbild-vaterunser-v2.png",hotspots:[{label:"Brot",x:11,y:69,correct:true},{label:"Schatztruhe",x:90,y:60,correct:false},{label:"offene Hände",x:75,y:76,correct:true},{label:"Waage",x:78,y:51,correct:true},{label:"verschlossene Tür",x:88,y:26,correct:false},{label:"betende Gruppe",x:65,y:26,correct:true}],rewards:{frieden:4,gerechtigkeit:5,vertrauen:6},card:{type:"Tugend-Karte",name:"Vertrauen"},success:"Ihr habt genau unterschieden: Brot, Vergebung, Gerechtigkeit und Gebet passen; Schatz und verschlossene Tür bleiben kritische Gegenbilder.",hint:"Die Labels erscheinen erst nach dem Anklicken. Begründet jedes Zeichen mit Mt 6: Brot, Schuldvergebung, Gottes Gerechtigkeit und Gebet."},
  {id:"vater-3",sector:"see",type:"path",difficulty:3,title:"Vaterunser-Lernpfad",story:"Eine Gruppe hat Angst, zu kurz zu kommen. Eine andere braucht Hilfe, und zugleich steht eine alte Schuld im Raum. Ihr prüft die Bitten des Vaterunsers als Entscheidungsweg.",source:"Mt 6,11-12.31-33 nach Luther 1912: Unser täglich Brot gib uns heute; vergib uns unsere Schuld; trachtet am ersten nach dem Reich Gottes und nach seiner Gerechtigkeit.",question:"Geht die vier Pfadkarten durch. Entscheidet jeweils, welche Deutung der Bitte am besten entspricht.",steps:[{title:"Brot",q:"Was bedeutet 'Unser täglich Brot gib uns heute' in der Situation?",answers:["Wir prüfen Bedarf und teilen fair, statt Vorräte aus Angst zu blockieren.","Wir sichern zuerst alles für uns.","Wir teilen planlos alles, ohne Verantwortung für morgen."],correct:0},{title:"Schuld",q:"Was folgt aus 'vergib uns unsere Schuld, wie wir unsern Schuldigern vergeben'?",answers:["Schuld benennen und einen Weg zur Vergebung öffnen.","Schuld verschweigen, damit es schneller ruhig wird.","Nur vergeben, wenn die andere Gruppe später nützlich ist."],correct:0},{title:"Gerechtigkeit",q:"Wie passt Mt 6,33 dazu?",answers:["Gottes Gerechtigkeit zuerst suchen: fair entscheiden, nicht nur bequem.","Gerechtigkeit später klären, Hauptsache wir gewinnen Zeit.","Gerechtigkeit heißt, die eigene Gruppe zu bevorzugen."],correct:0},{title:"Reflexion",q:"Welche Zusammenfassung trifft den Lernpfad?",answers:["Vertrauen wird konkret, wenn Brot, Schuld und Gerechtigkeit gemeinsam bedacht werden.","Vertrauen ersetzt jede Planung.","Beten ist nur privat und verändert Entscheidungen nicht."],correct:0}],rewards:{frieden:7,gerechtigkeit:7,vertrauen:9},card:{type:"Tugend-Karte",name:"Geteiltes Brot"},success:"Ihr habt das Vaterunser als Vertrauens- und Handlungssprache verstanden.",hint:"Das Vaterunser trennt Versorgung, Vergebung und Gerechtigkeit nicht. Jede gute Lösung nimmt alle drei auf."},
  {id:"gold-1",sector:"nazareth",type:"unlockword",difficulty:1,title:"Goldene Regel: Buchstaben freischalten",story:"Das Lösungswort wird nicht direkt abgefragt. Ihr erschließt es über Hilfsfragen zum Bibeltext und zwei Transferlevel.",source:"Mt 7,12 nach Luther 1912: Alles nun, was ihr wollt, daß euch die Leute tun sollen, das tut ihr ihnen auch.",question:"Löst die Hilfsfragen. Jede richtige Antwort schaltet Buchstaben frei. Gebt danach das Schlüsselwort ein.",answer:"Perspektivwechsel",alternatives:["perspektivwechsel"],clue:"PERSPEKTIVWECHSEL",challenges:[{q:"Hilfsfrage 1: Womit beginnt Mt 7,12?",answers:["Mit dem eigenen Wunsch an andere","Mit der Strafe für andere","Mit einer Sonderregel für Freunde"],correct:0,letters:"ERS"},{q:"Hilfsfrage 2: Was soll nach dem Vers daraus folgen?",answers:["Man tut den anderen entsprechend","Man wartet ab, ob andere zuerst handeln","Man entscheidet nur nach Vorteil"],correct:0,letters:"PEK"},{q:"Level 2: Was ist schwierigeres Textverständnis?",answers:["Der Vers dreht den eigenen Wunsch in aktives Handeln für andere.","Der Vers erlaubt Handeln nur, wenn andere zuerst fair sind.","Der Vers gilt nur für Menschen, die man mag."],correct:0,letters:"TIVW"},{q:"Level 3: Welche Konfliktanwendung passt?",answers:["Vor einer Antwort fragen: Wie wollte ich in dieser Lage behandelt werden?","Schnell reagieren, damit ich nicht schwach wirke.","Nur die eigene Gruppe schützen."],correct:0,letters:"ECHSEL"}],rewards:{frieden:5,gerechtigkeit:7,vertrauen:2},card:{type:"Tugend-Karte",name:"Perspektivwechsel"},success:"Richtig: Ihr habt das Schlüsselwort aus Textverständnis und Transfer erschlossen.",hint:"Die Goldene Regel beginnt beim eigenen Wunsch, endet aber nicht dort. Sie fordert aktives Tun an anderen."},
  {id:"gold-2",sector:"nazareth",type:"logic",difficulty:2,title:"Haus auf Fels und Sand",story:"Zwei Bauleute hören dieselbe Rede. Das Gleichnis fragt, ob aus Hören tragfähiges Tun wird.",source:"Mt 7,21.24-27 nach Luther 1912: Nicht jedes Herr, Herr trägt; wer hört und tut, baut auf Fels.",question:"Ordnet die Logik des Gleichnisses vom Hören zum tragfähigen Handeln.",items:["Jesu Rede hören","Jesu Rede tun","Haus auf Fels bauen","Sturm und Wasser halten dem Haus nicht stand"],correct:["Jesu Rede hören","Jesu Rede tun","Haus auf Fels bauen","Sturm und Wasser halten dem Haus nicht stand"],rewards:{frieden:3,gerechtigkeit:5,vertrauen:7},card:{type:"Gleichnis-Karte",name:"Haus auf Fels"},success:"Genau: Nicht das Hören allein trägt, sondern das Tun. Der Sturm prüft, ob das Fundament wirklich hält.",hint:"Im Gleichnis unterscheiden sich die Bauleute nicht beim Hören, sondern beim Tun und beim Fundament."},
  {id:"gold-3",sector:"nazareth",type:"finalquest",difficulty:3,title:"Finalquest: Felsbauer",story:"Im Finale entscheidet ihr in mehreren Schritten über Ausgrenzung, knappe Ressourcen, alte Schuld und eine hitzige Debatte. Eure Begründung wird zum Material für das Plenum.",source:"Mt 7,1-5.12.24 nach Luther 1912: Richtet nicht; Balken und Splitter prüfen; Goldene Regel tun; auf Fels bauen.",question:"Trefft drei Entscheidungen und formuliert eine Begründung: Warum baut eure Lösung auf Fels?",phases:[{title:"Selbstprüfung",q:"Was ist der erste Schritt nach Mt 7,1-5?",answers:["Den eigenen Anteil prüfen, bevor wir über andere urteilen.","Sofort festlegen, wer schuld ist.","Die lauteste Meinung übernehmen."],correct:0},{title:"Goldene Regel",q:"Welche Entscheidung setzt Mt 7,12 um?",answers:["Alle Seiten hören und fragen, wie wir selbst behandelt werden wollten.","Nur die eigene Gruppe schützen.","Abstimmen, ohne die Minderheit anzuhören."],correct:0},{title:"Felsbau",q:"Woran zeigt sich, dass Hören zum Tun wird?",answers:["Wir vereinbaren überprüfbare Schritte zum Schutz Schwächerer und zur Wiedergutmachung.","Wir nennen die Lösung gut, weil sie schnell ist.","Wir verschieben alles auf später."],correct:0}],rewards:{frieden:9,gerechtigkeit:10,vertrauen:7},card:{type:"Gleichnis-Karte",name:"Felsbauer"},success:"Ihr habt die Bergpredigt gebündelt: Selbstprüfung, Perspektivwechsel und überprüfbares Tun.",hint:"Felsbau ist nicht nur richtig reden. Die beste Lösung zeigt konkrete Schritte, die aus Jesu Rede folgen."}
];
sortTasksByLearningPath(TASKS);
const db=createDb(),STATE_KEY="bergpredigt-tablet-state-v5";let sessionId=getActiveSession()||randomSession(),groupId="",taskIndex=0,solved=new Set(),completedGames=new Set(),attempts=0,locked=false,excluded=false,liveChannel=null,sessionRows=[],sessionCompletion=new Map(),groupTarget=4,lastPromptSeen="",selectedAvatar=AVATARS[0].id,finaleSeen=false,feedbackSeen=new Set(),storySeen=new Set(),localScores={frieden:0,gerechtigkeit:0,vertrauen:0},localCards=[];setActiveSession(sessionId);
function sanitizeGroupId(value){return value.trim().toLowerCase().replace(/[^a-z0-9_-]/g,"").slice(0,24)}
function stateId(){return`${STATE_KEY}:${sessionId}:${groupId}`}
function saveState(){if(groupId)localStorage.setItem(stateId(),JSON.stringify({taskIndex,solved:[...solved],completedGames:[...completedGames],scores:localScores,cards:localCards,avatar:selectedAvatar}))}
function restoreState(){try{const saved=JSON.parse(localStorage.getItem(stateId())||"{}");taskIndex=Math.min(Number(saved.taskIndex)||0,TASKS.length);solved=new Set(saved.solved||[]);completedGames=new Set(saved.completedGames||[]);localScores={frieden:0,gerechtigkeit:0,vertrauen:0,...(saved.scores||{})};localCards=saved.cards||[];selectedAvatar=saved.avatar||selectedAvatar}catch{taskIndex=0;solved=new Set();completedGames=new Set();localScores={frieden:0,gerechtigkeit:0,vertrauen:0};localCards=[]}}
function saveAvatarState(){if(groupId){const saved=JSON.parse(localStorage.getItem(stateId())||"{}");localStorage.setItem(stateId(),JSON.stringify({...saved,avatar:selectedAvatar}))}}
function totalScore(){return VALUE_KEYS.reduce((sum,key)=>sum+(localScores[key]||0),0)}
function renderHud(){const hud=document.getElementById("gameHud");if(!hud)return;const rank=rankForScore(totalScore()),strongest=VALUE_KEYS.slice().sort((a,b)=>(localScores[b]||0)-(localScores[a]||0))[0];hud.innerHTML=`<div class="rank-card"><b>${rank.name}</b><span>${totalScore()} Kompasspunkte</span><small>Profil: ${VALUE_LABELS[strongest]}</small></div>${VALUE_KEYS.map(key=>`<div class="value-chip"><b>${VALUE_LABELS[key]}</b><span>${localScores[key]||0}</span><small>${key==="frieden"?"Versöhnung":key==="gerechtigkeit"?"Schutz & Recht":"Mut aus Vertrauen"}</small></div>`).join("")}<div class="card-chip"><b>Karten</b><span>${localCards.length}</span><small>Belege fürs Plenum</small></div>`}
function selectAvatar(id){selectedAvatar=AVATARS.some(avatar=>avatar.id===id)?id:AVATARS[0].id;document.querySelectorAll("[data-avatar-choice]").forEach(button=>button.classList.toggle("selected",button.dataset.avatarChoice===selectedAvatar))}
function renderAvatarPicker(){document.getElementById("avatarPicker").innerHTML=AVATARS.map(avatar=>`<button class="avatar-choice ${avatar.id===selectedAvatar?"selected":""}" type="button" data-avatar-choice="${avatar.id}" aria-pressed="${avatar.id===selectedAvatar}"><span class="avatar-token" style="--avatar-pos:${avatar.pos}"></span><b>${avatar.name}</b></button>`).join("");document.querySelectorAll("[data-avatar-choice]").forEach(button=>button.addEventListener("click",()=>{selectAvatar(button.dataset.avatarChoice);document.querySelectorAll("[data-avatar-choice]").forEach(item=>item.setAttribute("aria-pressed",String(item.dataset.avatarChoice===selectedAvatar)))}))}
function stationPart(index){const sector=TASKS[index]?.sector;if(!sector)return{part:0,total:0};const tasks=TASKS.filter(task=>task.sector===sector),part=TASKS.slice(0,index+1).filter(task=>task.sector===sector).length;return{part,total:tasks.length}}
function renderFogMap(){const current=TASKS[taskIndex]?.sector,isCoop=activeWorkMode(sessionRows)==="cooperative";document.getElementById("tabletFogMap").innerHTML=SECTORS.map((sector,i)=>{const state=sessionCompletion.get(sector.id)||{count:0,required:isCoop?groupTarget:1,complete:false},isOwnDone=solved.has(sector.id),isCurrent=sector.id===current,label=state.complete||isOwnDone||isCurrent?sector.name:`Modul ${i+1}`,detail=state.complete?"gemeinsam erschlossen":isCoop?`${state.count}/${state.required} Gruppenbeiträge`:isCurrent?"jetzt spielen":"noch offen";return`<div class="${state.complete||isOwnDone?"done":""} ${isCurrent?"current":""}"><img src="${sector.art}" alt=""><b>${label}</b><span>${detail}</span></div>`}).join("")}
function showPromptPopup(prompt){if(!prompt||prompt===lastPromptSeen)return;lastPromptSeen=prompt;document.getElementById("promptPopupText").textContent=prompt;document.getElementById("promptPopup").classList.remove("hidden")}
function showStoryPopup(task,module,force=false){if(!task||(!force&&storySeen.has(task.id)))return;storySeen.add(task.id);document.getElementById("storyPopupTitle").textContent=task.title;document.getElementById("storyPopupText").textContent=`${module.title}: ${task.story}`;document.getElementById("storyPopup").classList.remove("hidden")}
function renderProgress(){document.getElementById("sessionLabel").textContent=sessionId;document.getElementById("tabletProgress").innerHTML=SECTORS.map(sector=>`<span class="${solved.has(sector.id)?"done":""}" title="${sector.name}"></span>`).join("");renderFogMap();renderHud();document.getElementById("tabletLock").classList.toggle("hidden",!locked);document.getElementById("tabletExcluded").classList.toggle("hidden",!excluded);const mode=WORK_MODES[activeWorkMode(sessionRows)];document.getElementById("phaseBanner").textContent=`Phase: ${activePhase(sessionRows)} · Modus: ${mode.name}`;const prompt=activePrompt(sessionRows),box=document.getElementById("livePrompt");box.classList.toggle("hidden",!prompt);box.innerHTML=prompt?`<b>Live-Auftrag der Lehrkraft</b><span>${escapeHtml(prompt)}</span>`:"";showPromptPopup(prompt);if(finaleRequested(sessionRows)&&!finaleSeen){finaleSeen=true;document.getElementById("finalePrompt").classList.remove("hidden")}}
function biblePanelMarkup(sectorId){const panel=BIBLE_PANELS[sectorId];return panel?`<details class="bible-panel" open><summary>Bibeltext-Hilfe (${escapeHtml(panel.reference)})</summary><p>${escapeHtml(panel.text)}</p><small>Alle Spiele dieses Moduls sind nur mit diesem Textbezug lösbar.</small></details>`:""}
function rewardMarkup(task){return`<div class="reward-row">${VALUE_KEYS.map(key=>`<span>${VALUE_LABELS[key]} +${task.rewards?.[key]||0}</span>`).join("")}<span>${escapeHtml(task.card?.type||"Karte")}: ${escapeHtml(task.card?.name||"-")}</span><small>Punkte formen den Klassen-Kompass an der Tafel; Karten werden zu Belegen für die Debatte.</small></div>`}
function productMarkup(task,next){return(!next||next.sector!==task.sector)?`<section class="product-card"><h3>Anonymer Merksatz für die Tafel</h3><p>Formuliert einen Satz, den ihr aus diesem Modul ins Plenum mitnehmt.</p><textarea id="productText" maxlength="220" placeholder="Unser Merksatz ..."></textarea></section>`:""}
function debateMarkup(){return`<section class="debate-card"><p class="comic-kicker">Debatten-Finale</p><h2>${escapeHtml(DEBATE_FINALE.question)}</h2><p><b>Argumentkarten sind keine Zusatzpunkte.</b> Sie sind Belegkarten: Wählt eine Position und stützt sie mit Karten, Bibeltext und euren Entscheidungen. Eure Auswahl erscheint anonym in der Plenumsarena.</p><div class="debate-columns">${DEBATE_FINALE.positions.map((position,index)=>`<div><h3>Position ${index+1}</h3><p>${escapeHtml(position)}</p><div class="debate-drop" data-debate-slot="${index}"></div></div>`).join("")}</div><div class="debate-arguments">${DEBATE_FINALE.arguments.map(argument=>`<button class="argument-card" type="button">${escapeHtml(argument)}</button>`).join("")}</div><button class="comic-button" id="sendDebate" type="button">Argumente an Tafel senden</button></section>`}
function bindDebate(){document.querySelectorAll(".argument-card").forEach(button=>button.addEventListener("click",()=>{const side=button.dataset.side==="0"?"1":"0";button.dataset.side=side;document.querySelector(`[data-debate-slot="${side}"]`).append(button)}));document.getElementById("sendDebate")?.addEventListener("click",sendDebate)}
async function sendDebate(){const cards=[...document.querySelectorAll(".debate-drop .argument-card")].slice(0,4);for(const card of cards){await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`debate:${card.dataset.side||0}:${card.textContent.slice(0,180)}`})}document.getElementById("sendDebate").textContent="Gesendet"}
function showFeedbackCard(sectorId){if(feedbackSeen.has(sectorId))return;feedbackSeen.add(sectorId);document.getElementById("feedbackPopupText").textContent=feedbackFor(sectorId,sessionRows);document.getElementById("feedbackPopup").classList.remove("hidden")}
async function submitMiss(task){try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`miss:${taskIndex}:${task.type}:${task.sector}`})}catch(error){console.error(error)}}
async function submitProduct(sectorId){const text=document.getElementById("productText")?.value.trim().replace(/\s+/g," ").slice(0,220);if(!text)return;try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`product:${sectorId}:${text}`})}catch(error){console.error(error)}}
async function awardTask(task){if(completedGames.has(task.id))return;completedGames.add(task.id);VALUE_KEYS.forEach(key=>localScores[key]=(localScores[key]||0)+(task.rewards?.[key]||0));if(task.card)localCards.push(task.card);saveState();try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`score:${task.id}:${VALUE_KEYS.map(key=>`${key}=${task.rewards?.[key]||0}`).join(",")}`});if(task.card)await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`card:${task.card.type}:${task.card.name}`})}catch(error){console.error(error)}renderHud()}
function shuffle(items){return items.map((value,index)=>({value,index,sort:crypto.getRandomValues(new Uint32Array(1))[0]})).sort((a,b)=>a.sort-b.sort).map(item=>item)}
function optionMarkup(options){return shuffle(options).map(item=>`<option value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</option>`).join("")}
function choiceMarkup(task,multiple=false){const correct=Array.isArray(task.correct)?new Set(task.correct):new Set([task.correct]);return shuffle(task.answers).map(item=>`<label class="answer"><input type="${multiple?"checkbox":"radio"}" name="answer" data-correct="${correct.has(item.index)?"true":"false"}"><span>${escapeHtml(item.value)}</span></label>`).join("")}
function assignmentMarkup(task){return`<div class="assignment-game" data-assignment-type="${escapeHtml(task.type)}"><div class="assignment-slots">${task.items.map(([statement,correct],index)=>`<article class="match-card"><p>${escapeHtml(statement)}</p><button class="match-slot" type="button" data-correct="${escapeHtml(correct)}" data-slot="${index}"><span>Belegkarte ablegen</span></button></article>`).join("")}</div><div class="match-bank">${shuffle(task.correct).map(item=>`<button class="match-token" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-match" type="button">Zuordnung leeren</button></div>`}
function puzzleMarkup(task){return`<div class="puzzle-game"><div class="puzzle-slots">${task.correct.map((correct,index)=>`<button class="puzzle-slot" type="button" data-correct="${escapeHtml(correct)}" data-slot="${index}"><small>${index+1}</small><span>frei</span></button>`).join("")}</div><div class="puzzle-bank">${shuffle(task.items).map(item=>`<button class="puzzle-piece" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-puzzle" type="button">Puzzle leeren</button></div>`}
function miniMarkup(task){return`<div class="mini-quiz">${task.questions.map((question,index)=>`<fieldset><legend>${index+1}. ${escapeHtml(question.q)}</legend>${shuffle(question.answers).map(answer=>`<label class="answer"><input type="radio" name="mini-${index}" data-correct="${answer.index===question.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}</div>`}
function levelsMarkup(task){return`<div class="level-game">${task.levels.map((level,index)=>`<fieldset class="level-card"><legend>${escapeHtml(level.title)}</legend><p>${escapeHtml(level.q)}</p>${shuffle(level.answers).map(answer=>`<label class="answer"><input type="radio" name="level-${index}" data-correct="${answer.index===level.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}</div>`}
function wordMarkup(task){return`<div class="word-riddle"><p class="word-clue">${escapeHtml(task.clue||"")}</p><input class="word-input" name="word-answer" autocomplete="off" placeholder="Lösungswort eingeben"><small>Groß- und Kleinschreibung ist egal.</small></div>`}
function unlockWordMarkup(task){return`<div class="unlock-word-game"><div class="letter-safe" data-word="${escapeHtml(task.clue)}" aria-live="polite">${task.clue.split("").map((letter,index)=>`<span data-letter-index="${index}">${index===0?escapeHtml(letter):"_"}</span>`).join("")}</div>${task.challenges.map((challenge,index)=>`<fieldset class="unlock-challenge" data-letters="${escapeHtml(challenge.letters)}"><legend>${index+1}. ${escapeHtml(challenge.q)}</legend>${shuffle(challenge.answers).map(answer=>`<label class="answer"><input type="radio" name="unlock-${index}" data-correct="${answer.index===challenge.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}<input class="word-input" name="word-answer" autocomplete="off" placeholder="Freigeschaltetes Schlüsselwort eingeben"><small>Jede richtige Teilentscheidung deckt Buchstaben auf. Am Ende muss das ganze Wort stimmen.</small></div>`}
function dialogMarkup(task){return`<div class="dialog-game">${task.turns.map(([speaker,text],index)=>`<div class="speech ${index%2?"right":"left"}"><span class="avatar-token tiny" style="--avatar-pos:${AVATARS[index%AVATARS.length].pos}"></span><p><b>${escapeHtml(speaker)}</b>${escapeHtml(text)}</p></div>`).join("")}<h3>Antwort wählen</h3>${choiceMarkup(task)}</div>`}
function chatMarkup(task){return`<div class="chat-game">${task.chat.map((step,index)=>`<section class="chat-step ${index?"hidden":""}" data-chat-step="${index}"><div class="chat-bubble incoming"><b>${escapeHtml(step.from)}</b><span>${escapeHtml(step.text)}</span></div><div class="chat-choices">${shuffle(step.choices).map(choice=>`<button class="chat-choice" type="button" data-correct="${choice.index===step.correct?"true":"false"}">${escapeHtml(choice.value)}</button>`).join("")}</div><div class="chat-bubble system hidden">${escapeHtml(step.reply)}</div></section>`).join("")}</div>`}
function logicBuilderMarkup(task){return`<div class="foundation-game"><div class="foundation-slots">${task.correct.map((correct,index)=>`<button class="logic-slot" type="button" data-correct="${escapeHtml(correct)}"><small>${index+1}</small><span>Baustein setzen</span></button>`).join("")}</div><div class="foundation-bank">${shuffle(task.items).map(item=>`<button class="logic-stone" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-logic" type="button">Fundament neu bauen</button></div>`}
function pathMarkup(task){return`<div class="path-game">${task.steps.map((step,index)=>`<fieldset class="path-card"><legend>${index+1}. ${escapeHtml(step.title)}</legend><p>${escapeHtml(step.q)}</p>${shuffle(step.answers).map(answer=>`<label class="answer"><input type="radio" name="path-${index}" data-correct="${answer.index===step.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}</div>`}
function finalQuestMarkup(task){return`<div class="finalquest-game">${task.phases.map((phase,index)=>`<fieldset class="path-card"><legend>${index+1}. ${escapeHtml(phase.title)}</legend><p>${escapeHtml(phase.q)}</p>${shuffle(phase.answers).map(answer=>`<label class="answer"><input type="radio" name="final-${index}" data-correct="${answer.index===phase.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}<label class="reflection-label"><span>Begründung für die Plenumsarena</span><textarea id="finalReason" placeholder="Wir bauen auf Fels, weil ..."></textarea><small>Die Begründung hilft euch später beim Argumentieren. Sie wird nicht benotet.</small></label></div>`}
function wimmelMarkup(task){return`<div class="wimmel-progress"><b id="wimmelCount">0</b><span> / ${(task.hotspots||[]).filter(spot=>spot.correct).length} Funde</span></div><div class="wimmel-game" role="group" aria-label="KI-Wimmelbild"><img class="wimmel-image" src="${escapeHtml(task.image||"assets/images/wimmelbild-vaterunser-v2.png")}" alt="Comic-Wimmelbild zur Bergpredigt und zum Vaterunser">${task.hotspots.map((spot,index)=>`<button class="wimmel-spot" type="button" data-index="${index}" data-correct="${spot.correct?"true":"false"}" style="--x:${spot.x}%;--y:${spot.y}%" aria-label="Fundstelle ${index+1}"><span>${escapeHtml(spot.label)}</span></button>`).join("")}</div><div class="found-tray" id="foundTray"><small>Noch keine Funde.</small></div>`}
function answerMarkup(task){if(task.type==="mini")return miniMarkup(task);if(task.type==="levels")return levelsMarkup(task);if(task.type==="word")return wordMarkup(task);if(task.type==="unlockword")return unlockWordMarkup(task);if(task.type==="dialog")return dialogMarkup(task);if(task.type==="chat")return chatMarkup(task);if(task.type==="wimmel")return wimmelMarkup(task);if(task.type==="path")return pathMarkup(task);if(task.type==="finalquest")return finalQuestMarkup(task);if(["case","conflict","decode","rpg","trust"].includes(task.type))return choiceMarkup(task);if(["quest"].includes(task.type))return choiceMarkup(task,true);if(["puzzle"].includes(task.type))return puzzleMarkup(task);if(["sort","logic"].includes(task.type))return logicBuilderMarkup(task);if(["match","cards","compass"].includes(task.type))return assignmentMarkup(task);return choiceMarkup(task)}
function values(name){return[...document.querySelectorAll(`[name="${name}"]`)].map(input=>input.value)}
function normalizeWord(value){return String(value||"").trim().toLowerCase().replace(/\s+/g,"")}
function isCorrect(task){if(task.type==="mini")return task.questions.every((_,index)=>document.querySelector(`input[name="mini-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="levels")return task.levels.every((_,index)=>document.querySelector(`input[name="level-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="word"){const answer=normalizeWord(document.querySelector('[name="word-answer"]')?.value),valid=[task.answer,...(task.alternatives||[])].map(normalizeWord);return valid.includes(answer)}if(task.type==="unlockword"){const answer=normalizeWord(document.querySelector('[name="word-answer"]')?.value),valid=[task.answer,...(task.alternatives||[])].map(normalizeWord),questions=task.challenges.every((_,index)=>document.querySelector(`input[name="unlock-${index}"]:checked`)?.dataset.correct==="true");return questions&&valid.includes(answer)}if(task.type==="dialog")return document.querySelector('input[name="answer"]:checked')?.dataset.correct==="true";if(task.type==="chat")return task.chat.every((_,index)=>document.querySelector(`[data-chat-step="${index}"] .chat-choice.selected`)?.dataset.correct==="true");if(task.type==="wimmel"){const buttons=[...document.querySelectorAll(".wimmel-spot")];return buttons.every(button=>button.classList.contains("found")===(button.dataset.correct==="true"))}if(task.type==="path")return task.steps.every((_,index)=>document.querySelector(`input[name="path-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="finalquest")return task.phases.every((_,index)=>document.querySelector(`input[name="final-${index}"]:checked`)?.dataset.correct==="true");if(["case","conflict","decode","rpg","trust"].includes(task.type))return document.querySelector('input[name="answer"]:checked')?.dataset.correct==="true";if(task.type==="quest"){const inputs=[...document.querySelectorAll('input[name="answer"]')];return inputs.some(input=>input.checked)&&inputs.every(input=>input.checked===(input.dataset.correct==="true"))}if(task.type==="puzzle")return[...document.querySelectorAll(".puzzle-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);if(["sort","logic"].includes(task.type))return[...document.querySelectorAll(".logic-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);if(["match","cards","compass"].includes(task.type))return[...document.querySelectorAll(".match-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);return false}
function bindSpecialGames(){document.querySelectorAll(".puzzle-piece").forEach(piece=>piece.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".puzzle-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=piece.dataset.value;slot.querySelector("span").textContent=piece.dataset.value;piece.disabled=true}));document.querySelectorAll(".puzzle-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const piece=[...document.querySelectorAll(".puzzle-piece")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(piece)piece.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="frei"}));document.querySelector(".reset-puzzle")?.addEventListener("click",()=>{document.querySelectorAll(".puzzle-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="frei"});document.querySelectorAll(".puzzle-piece").forEach(piece=>piece.disabled=false)});document.querySelectorAll(".match-token").forEach(token=>token.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".match-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=token.dataset.value;slot.querySelector("span").textContent=token.dataset.value;token.disabled=true}));document.querySelectorAll(".match-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const token=[...document.querySelectorAll(".match-token")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(token)token.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="Belegkarte ablegen"}));document.querySelector(".reset-match")?.addEventListener("click",()=>{document.querySelectorAll(".match-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="Belegkarte ablegen"});document.querySelectorAll(".match-token").forEach(token=>token.disabled=false)});document.querySelectorAll(".logic-stone").forEach(stone=>stone.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".logic-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=stone.dataset.value;slot.querySelector("span").textContent=stone.dataset.value;stone.disabled=true}));document.querySelectorAll(".logic-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const stone=[...document.querySelectorAll(".logic-stone")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(stone)stone.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="Baustein setzen"}));document.querySelector(".reset-logic")?.addEventListener("click",()=>{document.querySelectorAll(".logic-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="Baustein setzen"});document.querySelectorAll(".logic-stone").forEach(stone=>stone.disabled=false)});const updateLetters=()=>{const safe=document.querySelector(".letter-safe");if(safe){const word=safe.dataset.word||"",revealed=new Set([0]);let cursor=1;document.querySelectorAll(".unlock-challenge").forEach(challenge=>{const checked=challenge.querySelector("input:checked"),count=String(challenge.dataset.letters||"").length;if(checked?.dataset.correct==="true")for(let i=0;i<count;i++)revealed.add(cursor+i);cursor+=count});[...safe.querySelectorAll("span")].forEach((span,index)=>span.textContent=revealed.has(index)?word[index]:"_")}};document.querySelectorAll(".unlock-challenge input").forEach(input=>input.addEventListener("change",updateLetters));document.querySelectorAll(".wimmel-spot").forEach(button=>button.addEventListener("click",()=>button.classList.toggle("selected")))}
function enhanceSpecialGames(task){
  document.querySelectorAll(".chat-choice").forEach(button=>button.addEventListener("click",()=>{
    const step=button.closest(".chat-step"),index=Number(step?.dataset.chatStep||0);
    step.querySelectorAll(".chat-choice").forEach(item=>item.classList.remove("selected","wrong"));
    button.classList.add("selected");
    if(button.dataset.correct==="true"){
      step.querySelector(".chat-bubble.system")?.classList.remove("hidden");
      document.querySelector(`[data-chat-step="${index+1}"]`)?.classList.remove("hidden");
    }else{
      button.classList.add("wrong");
    }
  }));
  const updateWimmel=()=>{
    const found=[...document.querySelectorAll(".wimmel-spot.found")],tray=document.getElementById("foundTray"),count=document.getElementById("wimmelCount");
    if(count)count.textContent=String(found.length);
    if(tray)tray.innerHTML=found.length?found.map(button=>`<span>${escapeHtml(button.textContent.trim())}</span>`).join(""):"<small>Noch keine Funde.</small>";
  };
  document.querySelectorAll(".wimmel-spot").forEach(button=>button.addEventListener("click",event=>{
    event.stopImmediatePropagation();
    if(button.dataset.correct==="true"){
      button.classList.add("found");
      button.classList.remove("miss");
    }else{
      button.classList.add("miss");
      setTimeout(()=>button.classList.remove("miss"),700);
    }
    updateWimmel();
  }));
}
function renderTask(){attempts=0;renderProgress();const card=document.getElementById("taskCard");if(taskIndex>=TASKS.length){card.className="task-card final-card";card.innerHTML=finaleRequested(sessionRows)?debateMarkup():"<p class='comic-kicker'>Mission geschafft</p><h2>Ihr seid bereit für das Finale!</h2><p>Wartet auf die Plenumsarena der Lehrkraft.</p>";bindDebate();return}const task=TASKS[taskIndex],next=TASKS[taskIndex+1],sector=SECTORS.find(s=>s.id===task.sector),module=moduleFor(task.sector,sessionRows),part=stationPart(taskIndex),isCoop=activeWorkMode(sessionRows)==="cooperative",state=sessionCompletion.get(sector.id)||{count:0,required:isCoop?groupTarget:1};card.className=`task-card task-type-${task.type}`;card.innerHTML=`<div class="station-header"><span class="station-number">${sector.name} · Spiel ${part.part}/${part.total} · Schwierigkeit ${task.difficulty}</span><b>${taskSkillLabel(task)}</b></div><p class="coop-note">${isCoop?`${state.count}/${state.required} aktive Gruppen haben dieses Modul gesichert.`:"Euer Modulabschluss kann die Tafel öffnen."}</p><section class="module-context"><p class="comic-kicker">${escapeHtml(module.title)}</p><p>${escapeHtml(module.narrative)}</p><small><b>Rangziel:</b> Suchender → Felsbauer</small></section>${biblePanelMarkup(task.sector)}${rewardMarkup(task)}<h2>${task.title}</h2><p class="story-bubble">${task.story}</p><p class="source">${task.source}</p><h3>${task.question}</h3><div class="answers">${answerMarkup(task)}</div>${productMarkup(task,next)}<div class="feedback hidden" id="feedback" aria-live="polite"></div><div class="task-actions"><button class="comic-button" id="checkAnswer" type="button">Spiel prüfen</button><button class="comic-button next-task hidden" id="nextTask" type="button">Weiter →</button></div>`;bindSpecialGames();document.getElementById("checkAnswer").addEventListener("click",checkAnswer);document.getElementById("nextTask").addEventListener("click",advance)}
function renderTask(){
  attempts=0;
  renderProgress();
  const card=document.getElementById("taskCard");
  if(taskIndex>=TASKS.length){
    card.className="task-card final-card";
    card.innerHTML=finaleRequested(sessionRows)?debateMarkup():"<p class='comic-kicker'>Mission geschafft</p><h2>Ihr seid bereit für das Finale!</h2><p>Wartet auf die Plenumsarena der Lehrkraft.</p>";
    bindDebate();
    return;
  }
  const task=TASKS[taskIndex],next=TASKS[taskIndex+1],sector=SECTORS.find(s=>s.id===task.sector),module=moduleFor(task.sector,sessionRows),part=stationPart(taskIndex),isCoop=activeWorkMode(sessionRows)==="cooperative",state=sessionCompletion.get(sector.id)||{count:0,required:isCoop?groupTarget:1};
  card.className=`task-card task-type-${task.type}`;
  card.innerHTML=`<div class="station-header"><span class="station-number">${sector.name} · Spiel ${part.part}/${part.total} · Schwierigkeit ${task.difficulty}</span><b>${taskSkillLabel(task)}</b></div><p class="coop-note">${isCoop?`${state.count}/${state.required} aktive Gruppen haben dieses Modul gesichert.`:"Euer Modulabschluss kann die Tafel öffnen."}</p><button class="mini-action story-reopen" id="showStoryAgain" type="button">Rahmenerzählung anzeigen</button>${biblePanelMarkup(task.sector)}<h2>${escapeHtml(task.title)}</h2><h3>${escapeHtml(task.question)}</h3><div class="answers">${answerMarkup(task)}</div>${productMarkup(task,next)}<div class="feedback hidden" id="feedback" aria-live="polite"></div><div class="task-actions"><button class="comic-button" id="checkAnswer" type="button">Spiel prüfen</button><button class="comic-button next-task hidden" id="nextTask" type="button">Weiter →</button></div>`;
  bindSpecialGames();
  enhanceSpecialGames(task);
  showStoryPopup(task,module);
  document.getElementById("showStoryAgain").addEventListener("click",()=>showStoryPopup(task,module,true));
  document.getElementById("checkAnswer").addEventListener("click",checkAnswer);
  document.getElementById("nextTask").addEventListener("click",advance);
}
async function checkAnswer(){if(locked||excluded)return;const task=TASKS[taskIndex],feedback=document.getElementById("feedback");if(!isCorrect(task)){attempts++;submitMiss(task);feedback.className="feedback bad";feedback.textContent=attempts>1?`Noch nicht tragfähig. Hinweis: ${task.hint}`:"Noch nicht. Nutzt den Bibeltext genau und besprecht eure Wahl.";return}feedback.className="feedback good";feedback.textContent=`✓ ${task.success}`;document.querySelectorAll(".task-card input,.task-card textarea,.task-card select,.task-card button:not(.next-task)").forEach(input=>input.disabled=true);document.getElementById("checkAnswer").classList.add("hidden");document.getElementById("nextTask").classList.remove("hidden");await awardTask(task)}
async function advance(){if(locked||excluded)return;const current=TASKS[taskIndex],next=TASKS[taskIndex+1],stationComplete=!next||next.sector!==current.sector,button=document.getElementById("nextTask");button.disabled=true;try{if(stationComplete&&!solved.has(current.sector)){await submitProduct(current.sector);await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:current.sector,status:"erledigt"});solved.add(current.sector)}taskIndex++;saveState();renderTask();if(stationComplete)showFeedbackCard(current.sector)}catch(error){console.error(error);button.disabled=false;document.getElementById("feedback").className="feedback bad";document.getElementById("feedback").textContent="Das Spiel ist gelöst, aber die Übertragung hat nicht geklappt. Bitte versucht es erneut."}}
async function refreshControl(){try{sessionRows=await readProgress(db,sessionId);locked=isSessionLocked(sessionRows);excluded=groupId?isGroupExcluded(sessionRows,groupId):false;groupTarget=effectiveGroupTargetFromRows(sessionRows);sessionCompletion=sectorCompletion(sessionRows);renderProgress();if(taskIndex>=TASKS.length)renderTask()}catch(error){console.error(error)}}
function subscribeControl(){if(!db)return;if(liveChannel)db.removeChannel(liveChannel);liveChannel=db.channel(`tablet-control-${sessionId}`).on("postgres_changes",{event:"INSERT",schema:"public",table:"fortschritt",filter:`session_id=eq.${sessionId}`},()=>refreshControl()).subscribe()}
document.getElementById("groupForm").addEventListener("submit",async event=>{event.preventDefault();groupId=sanitizeGroupId(document.getElementById("groupInput").value);const chosenAvatar=selectedAvatar;if(groupId.length<2)return;restoreState();selectedAvatar=chosenAvatar;saveAvatarState();try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"manual",payload:`avatar:${selectedAvatar}`})}catch(error){console.error(error)}await refreshControl();subscribeControl();document.getElementById("groupSetup").classList.add("hidden");document.getElementById("missionArea").classList.remove("hidden");document.getElementById("groupLabel").innerHTML=`<span class="avatar-token tiny" style="--avatar-pos:${avatarById(selectedAvatar).pos}"></span> Gruppe: ${escapeHtml(groupId)}`;renderTask()});
document.getElementById("changeGroup").addEventListener("click",()=>{groupId="";taskIndex=0;solved=new Set();completedGames=new Set();localScores={frieden:0,gerechtigkeit:0,vertrauen:0};localCards=[];document.getElementById("groupSetup").classList.remove("hidden");document.getElementById("missionArea").classList.add("hidden");document.getElementById("groupInput").focus()});
document.getElementById("closePromptPopup").addEventListener("click",()=>document.getElementById("promptPopup").classList.add("hidden"));
document.getElementById("closeFinalePrompt").addEventListener("click",()=>document.getElementById("finalePrompt").classList.add("hidden"));
document.getElementById("closeFeedbackPopup").addEventListener("click",()=>document.getElementById("feedbackPopup").classList.add("hidden"));
document.getElementById("closeStoryPopup").addEventListener("click",()=>document.getElementById("storyPopup").classList.add("hidden"));
setConnectionStatus(db?"Live verbunden":"Demo-Modus",Boolean(db));renderAvatarPicker();renderProgress();
